export async function resolveMetadata(
  tree: LoaderTree,
  pathname: Promise<string>,
  searchParams: Promise<ParsedUrlQuery>,
  errorConvention: MetadataErrorType | undefined,
  interpolatedParams: Params,
  metadataContext: MetadataContext,
  isRuntimePrefetchable: boolean
): Promise<ResolvedMetadata> {
  const metadataItems = await resolveMetadataItems(
    tree,
    searchParams,
    errorConvention,
    interpolatedParams,
    isRuntimePrefetchable
  )
  const workStore = workAsyncStorage.getStore()
  if (!workStore) {
    throw new InvariantError('Expected workStore to be initialized')
  }
  return accumulateMetadata(
    workStore.route,
    metadataItems,
    pathname,
    metadataContext
  )
}

export default function AppRouter({
  actionQueue,
  globalErrorState,
  webSocket,
  staticIndicatorState,
}: {
  actionQueue: AppRouterActionQueue
  globalErrorState: GlobalErrorState
  webSocket?: WebSocket
  staticIndicatorState?: StaticIndicatorState
}) {
  useNavFailureHandler()

  const router = (
    <Router
      actionQueue={actionQueue}
      globalError={globalErrorState}
      webSocket={webSocket}
      staticIndicatorState={staticIndicatorState}
    />
  )

  // At the very top level, use the default GlobalError component as the final fallback.
  // When the app router itself fails, which means the framework itself fails, we show the default error.
  return (
    <RootErrorBoundary errorComponent={DefaultGlobalError}>
      {router}
    </RootErrorBoundary>
  )
}

export async function matchesMiddleware<T extends FetchDataOutput>(
  options: MiddlewareEffectParams<T>
): Promise<boolean> {
  const matchers = await Promise.resolve(
    options.router.pageLoader.getMiddleware()
  )
  if (!matchers) return false

  const { pathname: asPathname } = parsePath(options.asPath)
  // remove basePath first since path prefix has to be in the order of `/${basePath}/${locale}`
  const cleanedAs = hasBasePath(asPathname)
    ? removeBasePath(asPathname)
    : asPathname
  const asWithBasePathAndLocale = addBasePath(
    addLocale(cleanedAs, options.locale)
  )

  // Check only path match on client. Matching "has" should be done on server
  // where we can access more info such as headers, HttpOnly cookie, etc.
  return matchers.some((m) =>
    new RegExp(m.regexp).test(asWithBasePathAndLocale)
  )
}

constructor(ctx: FileSystemCacheContext) {
  this.fs = ctx.fs
  this.flushToDisk = ctx.flushToDisk
  this.serverDistDir = ctx.serverDistDir
  this.revalidatedTags = ctx.revalidatedTags

  if (ctx.maxMemoryCacheSize) {
    if (!FileSystemCache.memoryCache) {
      if (FileSystemCache.debug) {
        console.log('FileSystemCache: using memory store for fetch cache')
      }

      FileSystemCache.memoryCache = getMemoryCache(ctx.maxMemoryCacheSize)
    } else if (FileSystemCache.debug) {
      console.log('FileSystemCache: memory store already initialized')
    }
  } else if (FileSystemCache.debug) {
    console.log('FileSystemCache: not using memory store for fetch cache')
  }
}

export function getMaxPostponedStateSize(
  configuredMaxPostponedStateSize: SizeLimit | undefined
): {
  maxPostponedStateSize: SizeLimit
  maxPostponedStateSizeBytes: number
} {
  const maxPostponedStateSize =
    configuredMaxPostponedStateSize ?? DEFAULT_MAX_POSTPONED_STATE_SIZE
  const maxPostponedStateSizeBytes = parseMaxPostponedStateSize(
    configuredMaxPostponedStateSize
  )

  if (maxPostponedStateSizeBytes === undefined) {
    throw new Error(INVALID_MAX_POSTPONED_STATE_SIZE_ERROR_MESSAGE)
  }

  return { maxPostponedStateSize, maxPostponedStateSizeBytes }
}

export function readRouteCacheEntry(
  now: number,
  key: RouteCacheKey
): RouteCacheEntry | null {
  const varyPath: RouteVaryPath = getRouteVaryPath(
    key.pathname,
    key.search,
    key.nextUrl
  )
  const isRevalidation = false
  const existingEntry = getFromCacheMap(
    now,
    getCurrentRouteCacheVersion(),
    routeCacheMap,
    varyPath,
    isRevalidation,
    false
  )
  if (existingEntry !== null) {
    return existingEntry
  }

  // No cache hit. Attempt to construct from template using the new
  // optimistic routing mechanism (pattern-based matching).
  if (process.env.__NEXT_OPTIMISTIC_ROUTING) {
    return matchKnownRoute(now, key.pathname, key.search)
  }

  return null
}

public setIsrStatus(key: string, value: boolean | undefined) {
  if (value === undefined) {
    this.appIsrManifestInner.remove(key)
  } else {
    this.appIsrManifestInner.set(key, value)
  }

  // Only send the ISR manifest to legacy clients, i.e. Pages Router clients,
  // or App Router clients that have Cache Components disabled. The ISR
  // manifest is only used to inform the static indicator, which currently
  // does not provide useful information if Cache Components is enabled due to
  // its binary nature (i.e. it does not support showing info for partially
  // static pages).
  this.bundler?.hotReloader?.sendToLegacyClients({
    type: HMR_MESSAGE_SENT_TO_BROWSER.ISR_MANIFEST,
    data: this.appIsrManifest,
  })
}

function getParamValueFromSegment(
  pathSegment: NormalizedAppRouteSegment,
  params: Params,
  paramType: DynamicParamTypes
): string {
  // If the segment is dynamic, resolve it from the params object
  if (pathSegment.type === 'dynamic') {
    return params[pathSegment.param.paramName] as string
  }

  // If the paramType indicates this is an intercepted param, strip the marker
  // that matches the interception marker in the param type
  const interceptionPrefix = interceptionPrefixFromParamType(paramType)
  if (interceptionPrefix === pathSegment.interceptionMarker) {
    return pathSegment.name.replace(pathSegment.interceptionMarker, '')
  }

  // For static segments, use the name
  return pathSegment.name
}

export function useErrorHandler(
  handleOnUnhandledError: ErrorHandler,
  handleOnUnhandledRejection: ErrorHandler
) {
  useEffect(() => {
    // Handle queued errors.
    errorQueue.forEach(handleOnUnhandledError)
    rejectionQueue.forEach(handleOnUnhandledRejection)

    // Listen to new errors.
    errorHandlers.push(handleOnUnhandledError)
    rejectionHandlers.push(handleOnUnhandledRejection)

    return () => {
      // Remove listeners.
      errorHandlers.splice(errorHandlers.indexOf(handleOnUnhandledError), 1)
      rejectionHandlers.splice(
        rejectionHandlers.indexOf(handleOnUnhandledRejection),
        1
      )

      // Reset error queues.
      errorQueue.splice(0, errorQueue.length)
      rejectionQueue.splice(0, rejectionQueue.length)
    }
  }, [handleOnUnhandledError, handleOnUnhandledRejection])
}

function generateCacheKey(request: Request): string {
  // We pick the fields that goes into the key used to dedupe requests.
  // We don't include the `cache` field, because we end up using whatever
  // caching resulted from the first request.
  // Notably we currently don't consider non-standard (or future) options.
  // This might not be safe. TODO: warn for non-standard extensions differing.
  // IF YOU CHANGE THIS UPDATE THE simpleCacheKey ABOVE.

  const filteredHeaders = Array.from(request.headers.entries()).filter(
    ([key]) => !headersToExcludeInCacheKey.has(key.toLowerCase())
  )

  return JSON.stringify([
    request.method,
    filteredHeaders,
    request.mode,
    request.redirect,
    request.credentials,
    request.referrer,
    request.referrerPolicy,
    request.integrity,
  ])
}

export function throwTurbopackInternalError(
  conversionError: Error | null,
  opts: TurbopackInternalErrorOpts
): never {
  if (conversionError != null) {
    // Somehow napi failed to convert `opts` to a JS object??? Just give up and throw that instead.
    throw new Error(
      'NAPI type conversion error in throwTurbopackInternalError',
      {
        cause: conversionError,
      }
    )
  }
  const err = new TurbopackInternalError(opts)
  const telemetry = traceGlobals.get('telemetry')
  if (telemetry) {
    telemetry.record(eventErrorThrown(err, opts.anonymizedLocation))
  } else {
    console.error('Expected `telemetry` to be set in globals')
  }
  throw err
}

export function resolveImages(
  images: OpenGraph['images'] | Twitter['images'],
  metadataBase: MetadataBaseURL,
  isStaticMetadataRouteFile: boolean
):
  | NonNullable<ResolvedMetadataWithURLs['twitter']>['images']
  | NonNullable<ResolvedMetadataWithURLs['openGraph']>['images'] {
  const resolvedImages = resolveAsArrayOrUndefined(images)
  if (!resolvedImages) return resolvedImages

  const nonNullableImages = []
  for (const item of resolvedImages) {
    const resolvedItem = resolveAndValidateImage(
      item,
      metadataBase,
      isStaticMetadataRouteFile
    )
    if (!resolvedItem) continue

    nonNullableImages.push(resolvedItem)
  }

  return nonNullableImages
}

export async function writeRootParamsTypes(
  manifest: RouteTypesManifest,
  filePath: string
) {
  const rootParams = manifest.rootParams

  await fs.promises.mkdir(path.dirname(filePath), { recursive: true })

  if (!rootParams.size) {
    // Write an empty declaration so the import in next-env.d.ts resolves.
    await fs.promises.writeFile(
      filePath,
      `// Type definitions for Next.js root params (next/root-params)\n// No root params detected.\nexport {}\n`
    )
    return
  }

  await fs.promises.writeFile(filePath, generateRootParamsTypes(rootParams))
}

function findSourceMapURL(filename: string): string | null {
  if (filename === '') {
    return null
  }

  if (
    filename.startsWith(document.location.origin) &&
    filename.includes('/_next/static')
  ) {
    // This is a request for a client chunk. This can only happen when
    // using Turbopack. In this case, since we control how those source
    // maps are generated, we can safely assume that the sourceMappingURL
    // is relative to the filename, with an added `.map` extension. The
    // browser can just request this file, and it gets served through the
    // normal dev server, without the need to route this through
    // the `/__nextjs_source-map` dev middleware.
    return `${filename}.map`
  }

  const url = new URL(pathname, document.location.origin)
  url.searchParams.set('filename', filename)

  return url.href
}

export function mountFormInstance(
  element: HTMLFormElement,
  href: string,
  router: AppRouterInstance,
  fetchStrategy: PrefetchTaskFetchStrategy
): void {
  const prefetchURL = coercePrefetchableUrl(href)
  if (prefetchURL === null) {
    // This href is not prefetchable, so we don't track it.
    // TODO: We currently observe/unobserve a form every time its href changes.
    // For Links, this isn't a big deal because the href doesn't usually change,
    // but for forms it's extremely common. We should optimize this.
    return
  }
  const instance: FormInstance = {
    router,
    fetchStrategy,
    isVisible: false,
    prefetchTask: null,
    prefetchHref: prefetchURL.href,
    setOptimisticLinkStatus: null,
  }
  observeVisibility(element, instance)
}

export function createInitialCacheNodeForHydration(
  navigatedAt: number,
  initialTree: RouteTree,
  seedData: CacheNodeSeedData | null,
  seedHead: HeadData,
  seedDynamicStaleAt: number
): NavigationTask {
  // Create the initial cache node tree, using the data embedded into the
  // HTML document.
  const accumulation: NavigationRequestAccumulation = {
    separateRefreshUrls: null,
    scrollRef: null,
  }
  const task = createCacheNodeOnNavigation(
    navigatedAt,
    initialTree,
    null,
    FreshnessPolicy.Hydration,
    seedData,
    seedHead,
    seedDynamicStaleAt,
    false,
    accumulation
  )
  return task
}

function accumulateScrollRef(
  freshness: FreshnessPolicy,
  cacheNode: CacheNode,
  accumulation: NavigationRequestAccumulation
): void {
  switch (freshness) {
    case FreshnessPolicy.Default:
    case FreshnessPolicy.Gesture:
    case FreshnessPolicy.RefreshAll:
    case FreshnessPolicy.HMRRefresh:
      if (accumulation.scrollRef === null) {
        accumulation.scrollRef = { current: true }
      }
      cacheNode.scrollRef = accumulation.scrollRef
      break
    case FreshnessPolicy.Hydration:
      // Initial render — no scroll.
      break
    case FreshnessPolicy.HistoryTraversal:
      // Back/forward — scroll restoration is handled separately.
      break
    default:
      freshness satisfies never
      break
  }
}

function patchRouterStateWithNewChildren(
  baseRouterState: FlightRouterState,
  newChildren: { [parallelRouteKey: string]: FlightRouterState }
): FlightRouterState {
  const clone: FlightRouterState = [baseRouterState[0], newChildren]
  // Based on equivalent logic in apply-router-state-patch-to-tree, but should
  // confirm whether we need to copy all of these fields. Not sure the server
  // ever sends, e.g. the refetch marker.
  if (2 in baseRouterState) {
    clone[2] = baseRouterState[2]
  }
  if (3 in baseRouterState) {
    clone[3] = baseRouterState[3]
  }
  if (4 in baseRouterState) {
    clone[4] = baseRouterState[4]
  }
  return clone
}

function reuseSharedCacheNode(
  dropPrefetchRsc: boolean,
  existingCacheNode: CacheNode
): CacheNode {
  // Clone the CacheNode that was already present in the previous tree.
  // Carry forward the scrollRef so scroll intent from a prior navigation
  // survives tree rebuilds (e.g. push + refresh in the same batch).
  // Carry forward the bfcacheId so shared-layout segments retain stable
  // identity across navigations.
  return createCacheNode(
    existingCacheNode.rsc,
    dropPrefetchRsc ? null : existingCacheNode.prefetchRsc,
    existingCacheNode.head,
    dropPrefetchRsc ? null : existingCacheNode.prefetchHead,
    existingCacheNode.bfcacheId,
    existingCacheNode.scrollRef
  )
}

function attachInvalidationListener(task: PrefetchTask): void {
  // This function is called whenever a prefetch task reads a cache entry. If
  // the task has an onInvalidate function associated with it — i.e. the one
  // optionally passed to router.prefetch(onInvalidate) — then we attach that
  // listener to the every cache entry that the task reads. Then, if an entry
  // is invalidated, we call the function.
  if (task.onInvalidate !== null) {
    if (invalidationListeners === null) {
      invalidationListeners = new Set([task])
    } else {
      invalidationListeners.add(task)
    }
  }
}

function createDetachedRouteCacheEntry(): PendingRouteCacheEntry {
  return {
    canonicalUrl: null,
    status: EntryStatus.Empty,
    blockedTasks: null,
    tree: null,
    metadata: null,
    // This is initialized to true because we don't know yet whether the route
    // could be intercepted. It's only set to false once we receive a response
    // from the server.
    couldBeIntercepted: true,
    // Similarly, we don't yet know if the route supports PPR.
    supportsPerSegmentPrefetching: false,
    renderedSearch: null,

    // Map-related fields
    ref: null,
    size: 0,
    // Since this is an empty entry, there's no reason to ever evict it. It will
    // be updated when the data is populated.
    staleAt: Infinity,
    version: getCurrentRouteCacheVersion(),
  }
}

async function verifyTypeScript(opts: SetupOpts) {
  const verifyResult = await verifyAndRunTypeScript({
    dir: opts.dir,
    distDir: opts.nextConfig.distDir,
    strictRouteTypes: Boolean(opts.nextConfig.experimental.strictRouteTypes),
    shouldRunTypeCheck: false,
    tsconfigPath: opts.nextConfig.typescript.tsconfigPath,
    typedRoutes: Boolean(opts.nextConfig.typedRoutes),
    disableStaticImages: opts.nextConfig.images.disableStaticImages,
    hasAppDir: !!opts.appDir,
    hasPagesDir: !!opts.pagesDir,
    appDir: opts.appDir,
    pagesDir: opts.pagesDir,
  })

  if (verifyResult.version) {
    return true
  }
  return false
}

export async function decodeStageUntilBoundary<T>(
  responseBodyClone: ReadableStream<Uint8Array>,
  byteLength: number,
  headers: RequestHeaders | undefined
): Promise<T> {
  // Buffer the truncated stream into a single chunk before passing it to
  // Flight. This ensures all model data is available synchronously, which is
  // required for readVaryParams to synchronously read the thenable status.
  const { stream } = await createNonTaskyPrefetchResponseStream(
    responseBodyClone,
    byteLength
  )

  return createFromNextReadableStream<T>(stream, headers, {
    allowPartialStream: true,
  })
}

export function readVaryParams(
  thenable: VaryParamsThenable
): VaryParams | null {
  // Attach a no-op listener to force Flight to synchronously resolve the
  // thenable. When a thenable arrives from the Flight stream, it may be in an
  // intermediate 'resolved_model' state (data received but not unwrapped).
  // Calling .then() triggers Flight to transition it to 'fulfilled', making
  // the value available synchronously. React uses this same optimization
  // internally to avoid unnecessary microtasks.
  thenable.then(noop)
  // If the thenable is still not 'fulfilled' after calling .then(), the server
  // failed to resolve it before the stream ended. Treat as unknown.
  if (thenable.status !== 'fulfilled') {
    return null
  }
  return thenable.value
}

export function handleConsoleError(
  originError: unknown,
  consoleErrorArgs: any[]
) {
  let error: Error
  const { environmentName } = parseConsoleArgs(consoleErrorArgs)
  if (isError(originError)) {
    error = createConsoleError(originError, environmentName)
  } else {
    error = createConsoleError(
      formatConsoleArgs(consoleErrorArgs),
      environmentName
    )
  }
  setOwnerStackIfAvailable(error)

  errorQueue.push(error)
  for (const handler of errorHandlers) {
    // Delayed the error being passed to React Dev Overlay,
    // avoid the state being synchronously updated in the component.
    queueMicroTask(() => {
      handler(error)
    })
  }
}

create(context) {
  return {
    VariableDeclaration(node) {
      // Checks node.declarations array for variable with id.name of `module`
      const moduleVariableFound = node.declarations.some((declaration) => {
        if ('name' in declaration.id) {
          return declaration.id.name === 'module'
        }
        return false
      })

      // Return early if no `module` variable is found
      if (!moduleVariableFound) {
        return
      }

      context.report({
        node,
        message: `Do not assign to the variable \`module\`. See: ${url}`,
      })
    },
  }
}

export async function createCallbackUrl({
  options,
  paramValue,
  cookieValue,
}: CreateCallbackUrlParams) {
  const { url, callbacks } = options

  let callbackUrl = url.origin

  if (paramValue) {
    // If callbackUrl form field or query parameter is passed try to use it if allowed
    callbackUrl = await callbacks.redirect({
      url: paramValue,
      baseUrl: url.origin,
    })
  } else if (cookieValue) {
    // If no callbackUrl specified, try using the value from the cookie if allowed
    callbackUrl = await callbacks.redirect({
      url: cookieValue,
      baseUrl: url.origin,
    })
  }

  return {
    callbackUrl,
    // Save callback URL in a cookie so that it can be used for subsequent requests in signin/signout/callback flow
    callbackUrlCookie: callbackUrl !== cookieValue ? callbackUrl : undefined,
  }
}

public _write(
  chunk: Buffer | string,
  _encoding: string,
  callback: (error?: Error | null) => void
) {
  this.write(chunk)

  // According to Node.js documentation, the callback MUST be invoked to
  // signal that the write completed successfully. If this callback is not
  // invoked, the 'finish' event will not be emitted.
  //
  // https://nodejs.org/docs/latest-v16.x/api/stream.html#writable_writechunk-encoding-callback
  //
  // If the stream was destroyed due to an error, we should propagate it
  if (this.destroyed && this.errored) {
    callback(this.errored)
  } else {
    callback()
  }
}

export default function createTranslatorImpl<
  Messages extends AbstractIntlMessages,
  NestedKey extends NestedKeyOf<Messages>
>(
  {messages, namespace, ...rest}: CreateTranslatorImplProps<Messages>,
  namespacePrefix: string
) {
  // The `namespacePrefix` is part of the type system.
  // See the comment in the function invocation.
  messages = messages[namespacePrefix] as Messages;
  namespace = resolveNamespace(namespace, namespacePrefix) as NestedKey;

  return createBaseTranslator<Messages, NestedKey>({
    ...rest,
    messages,
    namespace
  });
}
